import 'package:equatable/equatable.dart'; class TrendingSearch extends Equatable{final String keyword; final int count; const TrendingSearch({required this.keyword,required this.count}); factory TrendingSearch.fromMap(Map<String,dynamic> map)=>TrendingSearch(keyword:map['keyword'] as String? ?? '',count:(map['count'] as num?)?.toInt()??0); @override List<Object?> get props=>[keyword,count];}
